import 'package:flutter/material.dart';import 'package:flutter/services.dart';import 'package:provider/provider.dart';import 'design_system/app_colors.dart';import 'design_system/app_spacing.dart';import 'design_system/app_theme.dart';import 'design_system/app_typography.dart';import 'providers/insights_provider.dart';import 'screens/insights/insights_dashboard_screen.dart';class MyApp extends StatelessWidget {  const MyApp({super.key});  @override  Widget build(BuildContext context) {    return MultiProvider(      providers: [        ChangeNotifierProvider(create: (_) => InsightsProvider()),      ],      child: MaterialApp(        title: 'Smart Spend Insights',        theme: AppTheme.darkTheme,        home: const HomeScreen(),        debugShowCheckedModeBanner: false,      ),    );  }}class HomeScreen extends StatefulWidget {  const HomeScreen({super.key});  @override  State<HomeScreen> createState() => _HomeScreenState();}@overrideclass _HomeScreenState extends State<HomeScreen> {  int _selectedIndex = 0;  static const List<Widget> _widgetOptions = <Widget>[    Text('Home Screen Placeholder'),    InsightsDashboardScreen(),    Text('Payments Screen Placeholder'),    Text('Profile Screen Placeholder'),  ];  void _onItemTapped(int index) {    HapticFeedback.lightImpact();    setState(() {      _selectedIndex = index;    });  }  @override  Widget build(BuildContext context) {    return Scaffold(      body: Center(        child: _widgetOptions.elementAt(_selectedIndex),      ),      bottomNavigationBar: Container(        height: AppSpacing.navBarHeight,        decoration: BoxDecoration(          color: AppColors.surface,          boxShadow: [            BoxShadow(              color: Colors.black.withOpacity(0.3),              offset: const Offset(0, -2),              blurRadius: 10,            ),          ],        ),        child: BottomNavigationBar(          items: <BottomNavigationBarItem>[            _buildNavItem(Icons.home_outlined, 'Home', 0),            _buildNavItem(Icons.insights_outlined, 'Insights', 1),            _buildNavItem(Icons.payment_outlined, 'Payments', 2),            _buildNavItem(Icons.person_outline, 'Profile', 3),          ],          currentIndex: _selectedIndex,          onTap: _onItemTapped,          backgroundColor: Colors.transparent, // Handled by container          elevation: 0,          selectedItemColor: AppColors.primary,          unselectedItemColor: AppColors.inactiveIcon,          selectedLabelStyle: AppTypography.navLabel.copyWith(color: AppColors.textPrimary),          unselectedLabelStyle: AppTypography.navLabel.copyWith(color: AppColors.inactiveIcon),          type: BottomNavigationBarType.fixed,        ),      ),    );  }  BottomNavigationBarItem _buildNavItem(IconData icon, String label, int index) {    final bool isActive = _selectedIndex == index;    return BottomNavigationBarItem(      icon: Column(        mainAxisSize: MainAxisSize.min,        children: [          Icon(icon, size: AppSpacing.iconSizeMedium),          if (isActive)            Container(              margin: const EdgeInsets.only(top: 2),              height: 2,              width: 24,              decoration: BoxDecoration(                color: AppColors.primary,                borderRadius: BorderRadius.circular(1),                boxShadow: [                  BoxShadow(                    color: AppColors.primary.withOpacity(0.5),                    blurRadius: 5,                    spreadRadius: 1,                  ),                ],              ),            ),        ],      ),      label: label,    );  }}void main() {  WidgetsFlutterBinding.ensureInitialized();  SystemChrome.setPreferredOrientations([DeviceOrientation.portraitUp]);  runApp(const MyApp());}